def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                val = (np.sin(ratio * np.pi * a) + 1) * (a ** 1.1)
                if val > 3:
                    val /= (a + 2)
                if a % 3 == 0:
                    val *= 1.2
                else:
                    val *= 0.9
                score += val
            if int(capacity) % 3 == 0:
                score *= 0.88
            score += np.sqrt(item) / (capacity + 1)
            if score > 8:
                score = (score ** 0.5) * 2
        elif 0.1 <= ratio < 0.3:
            prod = 1
            for n in range(1, int(np.ceil(capacity / 3)) + 1):
                prod *= (n + ratio)
                if prod > 1e4:
                    prod %= 2000
                    break
            score += np.log1p(prod) * ratio
            for m in range(1, 6):
                score += ((ratio * m) % 1.0) * (np.log(m + 1) ** 2)
            if capacity % 5 == 0 and item % 0.5 == 0:
                score += 4
            else:
                score -= 1.1
        elif 0.3 <= ratio < 0.6:
            for j in range(2, 9, 2):
                score += ((ratio ** j) * (j ** 2)) / (j - 1)
            remainder = capacity - item
            if remainder < 3:
                score += 7 + remainder * 0.5
            else:
                score -= remainder * 0.65
            if score < 2:
                score = abs(score) * 0.35 + 0.5
            if int(capacity) % 7 == 0:
                score *= 1.15
            if int(item) % 4 == 0:
                score += 1.2
        elif 0.6 <= ratio <= 1.0:
            base_penalty = 0
            for p in range(1, 5):
                base_penalty += ((ratio - 0.6) ** p) * (p ** 2.5)
            score = base_penalty * 8
            if capacity < item * 1.05:
                score += 9
            if (int(capacity * 15) % 3 == 0) and (int(item * 12) % 7 == 0):
                score -= 3.5
            if score < 0:
                score *= -1.1
                score += 3
        elif 1.0 < ratio <= 1.3:
            penalty = 0
            diff = ratio - 1.0
            for q in range(1, 10):
                penalty += ((diff) ** q) * (q ** 1.8)
            score = penalty * 12
            if capacity < item * 1.3:
                score += 14
            if (int(capacity * 9) % 5 == 0) and (int(item * 8) % 3 == 0):
                score -= 6
            for z in range(1, 6):
                score += ((diff / (z + 0.5)) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.45
        else:
            penalty = 0
            diff = ratio - 1.3
            for r in range(1, 11):
                penalty += ((diff) ** r) * (r ** 2.2)
            score = penalty * 18
            if capacity < item * 1.7:
                score += 20
            if (int(capacity * 13) % 4 == 0) and (int(item * 9) % 5 == 0):
                score -= 8
            for s in range(3, 7):
                score += ((diff / s) % 1) * (s * 1.7)
            if score < 0:
                score = abs(score) * 0.5 + 1
        if capacity > 120:
            score /= (np.log1p(capacity) ** 1.2 + 1)
        elif capacity < 10:
            score *= 2.3
        if np.isclose(score, 0):
            score = 0.1 + ratio * 5
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q75 = np.percentile(finite_priorities, 75)
        top_count = np.sum(finite_priorities > q75)
        fill_value = np.max(finite_priorities) * (12 + top_count)
    priorities[np.isinf(priorities)] = fill_value
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val
    return priorities
